import{_ as e,a,b as d,c as r,d as o}from"./chunks/编辑配置.T0puvWjh.js";import{_ as l,o as i,c as n,a2 as s}from"./chunks/framework.DnrXFDHb.js";const T=JSON.parse('{"title":"Додавання каналу Telegram","description":"","frontmatter":{},"headers":[],"relativePath":"uk-UA/upload/telegram.md","filePath":"uk-UA/upload/telegram.md","lastUpdated":1781962217000}'),h={name:"uk-UA/upload/telegram.md"};function c(p,t,m,g,b,u){return i(),n("div",null,[...t[0]||(t[0]=[s('<h1 id="додавання-каналу-telegram" tabindex="-1">Додавання каналу Telegram <a class="header-anchor" href="#додавання-каналу-telegram" aria-label="Permalink to &quot;Додавання каналу Telegram&quot;">​</a></h1><h2 id="що-підготувати-заздалегідь" tabindex="-1">Що підготувати заздалегідь <a class="header-anchor" href="#що-підготувати-заздалегідь" aria-label="Permalink to &quot;Що підготувати заздалегідь&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Потрібно</th><th>Навіщо це потрібно</th></tr></thead><tbody><tr><td>Обліковий запис Telegram</td><td>Для створення бота та каналу, у якому зберігатимуться файли.</td></tr><tr><td><code>@BotFather</code></td><td>Через нього створюється Telegram-бот.</td></tr><tr><td>Канал Telegram</td><td>Кінцеве місце зберігання файлів.</td></tr><tr><td><code>@userinfobot</code></td><td>Допомагає отримати <code>Chat ID</code> каналу.</td></tr></tbody></table><h2 id="де-додати-канал" tabindex="-1">Де додати канал <a class="header-anchor" href="#де-додати-канал" aria-label="Permalink to &quot;Де додати канал&quot;">​</a></h2><ol><li>Відкрийте системні налаштування.</li><li>Перейдіть до налаштувань завантаження.</li><li>Натисніть Add Channel у правому верхньому куті.</li><li>Виберіть <code>Telegram</code>.</li></ol><h2 id="поля-налаштування" tabindex="-1">Поля налаштування <a class="header-anchor" href="#поля-налаштування" aria-label="Permalink to &quot;Поля налаштування&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Поле</th><th>Що означає</th><th>Обов&#39;язково</th></tr></thead><tbody><tr><td>Назва каналу</td><td>Зручна назва, наприклад &quot;Telegram Primary&quot;.</td><td>Так</td></tr><tr><td>Активний</td><td>Увімкнення або вимкнення цього каналу.</td><td>Рекомендовано</td></tr><tr><td>Bot Token</td><td>Токен вашого Telegram-бота.</td><td>Так</td></tr><tr><td>Session ID (Chat ID)</td><td>Ідентифікатор Telegram-каналу.</td><td>Так</td></tr><tr><td>Relay Proxy URL (необов&#39;язково)</td><td>Використовуйте лише тоді, коли доступ до Telegram нестабільний. Вкажіть повну адресу проксі, з <code>https://</code>.</td><td>Ні</td></tr><tr><td>Примітка</td><td>Нотатки для подальшого обслуговування.</td><td>Ні</td></tr></tbody></table><h2 id="налаштування" tabindex="-1">Налаштування <a class="header-anchor" href="#налаштування" aria-label="Permalink to &quot;Налаштування&quot;">​</a></h2><h3 id="_1-створіть-telegram-бота" tabindex="-1">1. Створіть Telegram-бота <a class="header-anchor" href="#_1-створіть-telegram-бота" aria-label="Permalink to &quot;1. Створіть Telegram-бота&quot;">​</a></h3><ol><li>Відкрийте Telegram і знайдіть <code>@BotFather</code>.</li><li>Відкрийте чат і натисніть <code>Start</code>.</li><li>Надішліть <code>/newbot</code>.</li><li>За підказками введіть відображувану назву бота.</li><li>За підказками введіть username бота. Зазвичай він має закінчуватися на <code>bot</code>.</li><li>Після створення бота <code>@BotFather</code> поверне токен.</li></ol><p>Саме цей токен потрібно ввести в ImgBed у полі <code>Bot Token</code>.</p><p><img src="'+e+'" alt="Збережіть токен бота" loading="lazy"></p><h3 id="_2-створіть-канал" tabindex="-1">2. Створіть канал <a class="header-anchor" href="#_2-створіть-канал" aria-label="Permalink to &quot;2. Створіть канал&quot;">​</a></h3><ol><li>У Telegram натисніть New Channel.</li><li>Введіть назву каналу.</li><li>Завершіть створення каналу.</li></ol><p>Можна використовувати і публічний, і приватний канал.</p><p><img src="'+a+'" alt="Створення каналу" loading="lazy"></p><h3 id="_3-додаите-бота-до-каналу" tabindex="-1">3. Додайте бота до каналу <a class="header-anchor" href="#_3-додаите-бота-до-каналу" aria-label="Permalink to &quot;3. Додайте бота до каналу&quot;">​</a></h3><ol><li>Відкрийте щойно створений канал.</li><li>Перейдіть до налаштувань каналу.</li><li>Додайте учасника або адміністратора.</li><li>Знайдіть username створеного бота.</li><li>Додайте бота до каналу.</li></ol><p>Щоб завантаження працювали стабільно, краще надати боту права адміністратора.</p><p><img src="'+d+'" alt="Запросіть бота до каналу" loading="lazy"></p><h3 id="_4-отримаите-id-каналу-через-user-info-get-id-idbot" tabindex="-1">4. Отримайте ID каналу через User Info - Get ID - IDbot <a class="header-anchor" href="#_4-отримаите-id-каналу-через-user-info-get-id-idbot" aria-label="Permalink to &quot;4. Отримайте ID каналу через User Info - Get ID - IDbot&quot;">​</a></h3><ol><li>У Telegram знайдіть <code>@userinfobot</code>. Зазвичай він відображається як <code>User Info - Get ID - IDbot</code>.</li><li>Відкрийте чат і натисніть <code>Start</code>.</li><li>У варіантах бота виберіть <code>Channel</code>.</li><li>У вікні вибору повідомлення виберіть потрібний канал і надішліть його до <code>@userinfobot</code>.</li><li>Коли <code>@userinfobot</code> поверне результат, скопіюйте число в полі <code>Id: -100...</code>.</li></ol><p>Число, що починається з <code>-100</code>, і є значенням <code>Session ID (Chat ID)</code>, яке потрібне ImgBed.</p><p><img src="'+r+'" alt="Отримання ID каналу" loading="lazy"></p><h3 id="_5-заповніть-канал-telegram-в-imgbed" tabindex="-1">5. Заповніть канал Telegram в ImgBed <a class="header-anchor" href="#_5-заповніть-канал-telegram-в-imgbed" aria-label="Permalink to &quot;5. Заповніть канал Telegram в ImgBed&quot;">​</a></h3><p>Поверніться до діалогу налаштування каналу й заповніть поля так:</p><table tabindex="0"><thead><tr><th>Поле в інтерфейсі</th><th>Значення</th></tr></thead><tbody><tr><td>Channel Identifier</td><td>Власна назва каналу, наприклад <code>TelegramPrimary</code>.</td></tr><tr><td>Active</td><td>Рекомендовано увімкнути.</td></tr><tr><td>Bot Token</td><td>Токен бота з <code>@BotFather</code>.</td></tr><tr><td>Session ID (Chat ID)</td><td>Число <code>-100...</code>, яке повернув <code>@userinfobot</code>.</td></tr><tr><td>Relay Proxy URL (необов&#39;язково)</td><td>Лише за потреби, наприклад <code>https://your-tg-proxy.example.com</code>.</td></tr><tr><td>Remark</td><td>Необов&#39;язкові нотатки.</td></tr></tbody></table><p>Коли все заповнено, натисніть Save.</p><p><img src="'+o+`" alt="Редагування конфігурації" loading="lazy"></p><h2 id="як-перевірити" tabindex="-1">Як перевірити <a class="header-anchor" href="#як-перевірити" aria-label="Permalink to &quot;Як перевірити&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Перевірка</th><th>Як перевірити</th></tr></thead><tbody><tr><td>Картка каналу з&#39;явилася</td><td>Після збереження на сторінці налаштувань завантаження має бути картка Telegram-каналу.</td></tr><tr><td>Канал можна ввімкнути</td><td>Перемикач Active має залишатися увімкненим.</td></tr><tr><td>Конфігурацію збережено</td><td>У деталях має бути видно, що Bot Token і Chat ID збережені.</td></tr><tr><td>Завантаження працює</td><td>Завантажте тестове зображення й переконайтеся, що воно з&#39;явилося в цільовому Telegram-каналі.</td></tr></tbody></table><h2 id="короткии-чекліст" tabindex="-1">Короткий чекліст <a class="header-anchor" href="#короткии-чекліст" aria-label="Permalink to &quot;Короткий чекліст&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Створити бота через @BotFather</span></span>
<span class="line"><span>-&gt; Зберегти Bot Token</span></span>
<span class="line"><span>-&gt; Створити Telegram-канал</span></span>
<span class="line"><span>-&gt; Додати бота до каналу та надати права адміністратора</span></span>
<span class="line"><span>-&gt; Знайти @userinfobot і вибрати Channel</span></span>
<span class="line"><span>-&gt; Переслати будь-яке повідомлення з каналу до @userinfobot</span></span>
<span class="line"><span>-&gt; Скопіювати повернений Id: -100...</span></span>
<span class="line"><span>-&gt; Ввести Bot Token і Chat ID в ImgBed</span></span>
<span class="line"><span>-&gt; Зберегти та завантажити тестове зображення</span></span></code></pre></div><h2 id="посилання" tabindex="-1">Посилання <a class="header-anchor" href="#посилання" aria-label="Permalink to &quot;Посилання&quot;">​</a></h2><ol><li>Telegram bots: <a href="https://core.telegram.org/bots" target="_blank" rel="noreferrer">https://core.telegram.org/bots</a></li><li>Telegram Bot API: <a href="https://core.telegram.org/bots/api" target="_blank" rel="noreferrer">https://core.telegram.org/bots/api</a></li></ol>`,35)])])}const I=l(h,[["render",c]]);export{T as __pageData,I as default};
